import os
import glob
import numpy as np
import torch
from torch.utils.data import Dataset, DataLoader
import rasterio

# Sentinel-2 L2A per-band normalization constants
# Order matches GEE export: B1, B2, B3, B4, B5, B6, B7, B8, B8A, B9, B11, B12
# (B10 is absent, omitted by S2_SR_HARMONIZED)

# ── Per-band normalization constants ──────────────────────────────────────────
# Loaded from data/band_stats.npz, which is generated by compute_band_stats.py.
# Run script ONCE before training. Falls back to rough placeholders if the file doesn't exist yet.
_STATS_PATH = "data/band_stats.npz"

if os.path.exists(_STATS_PATH):
    _stats    = np.load(_STATS_PATH)
    BAND_MEAN = _stats["mean"].astype(np.float32)
    BAND_STD  = _stats["std"].astype(np.float32)
    print(f"[prepare_data] Loaded band stats from {_STATS_PATH}")
else:
    print(f"[prepare_data] WARNING: {_STATS_PATH} not found — using placeholder stats.")
    print( "               Run compute_band_stats.py before training for accurate normalization.")
    BAND_MEAN = np.array([
        300.0,  400.0,  500.0,  550.0,  600.0,  650.0,
        700.0,  750.0,  780.0,  200.0, 1000.0,  900.0
    ], dtype=np.float32)
    BAND_STD = np.array([
        400.0,  500.0,  600.0,  700.0,  700.0,  750.0,
        800.0,  900.0,  900.0,  300.0, 1500.0, 1400.0
    ], dtype=np.float32)

def compute_index(band_a, band_b):
    """Generic normalized difference index: (A - B) / (A + B)"""
    return (band_a - band_b) / (band_a + band_b + 1e-6)

class ShorelineDataset(Dataset):
    def __init__(self, img_paths, mask_paths, selected_bands=None, compute_fn=None):
        self.imgs           = img_paths
        self.masks          = mask_paths
        self.selected_bands = selected_bands
        self.compute_fn     = compute_fn   # None | "ndvi" | "ndmi" | "ndwi"

    def __getitem__(self, idx):
        # ---- Read image (multiband GeoTIFF) ----
        with rasterio.open(self.imgs[idx]) as src:
            image = src.read().astype(np.float32)  # (bands, H, W)

        np.nan_to_num(image, copy=False, nan=0.0, posinf=0.0, neginf=0.0)

        if self.compute_fn is None:
            # Raw band selection — same as before
            image = image[self.selected_bands, :, :]
            mean  = BAND_MEAN[self.selected_bands, np.newaxis, np.newaxis]
            std   = BAND_STD[self.selected_bands,  np.newaxis, np.newaxis]
            image = (image - mean) / (std + 1e-6)

        else:
            # Index mode: selected_bands = [band_a_idx, band_b_idx]
            band_a = image[self.selected_bands[0]]   # (H, W)
            band_b = image[self.selected_bands[1]]   # (H, W)
            index  = compute_index(band_a, band_b)   # (H, W), range ~[-1, 1]
            image  = index[np.newaxis, :, :]         # (1, H, W)
            # Index values are already ~[-1,1]; just clip for safety
            image  = np.clip(image, -1.0, 1.0)

        with rasterio.open(self.masks[idx]) as src:
            mask = src.read(1)

        np.nan_to_num(mask, copy=False, nan=0.0)
        mask = (mask > 0).astype(np.uint8)

        return torch.from_numpy(image), torch.from_numpy(mask).long()
    
    def __len__(self):
        return len(self.imgs)


def prepare_train_val_path(root_dir):
    train_img_dir = os.path.join(root_dir, "train", "images")
    train_mask_dir = os.path.join(root_dir, "train", "masks")

    train_imgs = sorted(glob.glob(os.path.join(train_img_dir, "img*.tif")))
    train_masks = [os.path.join(train_mask_dir, os.path.basename(p).replace("img", "mask")) for p in train_imgs]

    val_img_dir = os.path.join(root_dir, "val", "images")
    val_mask_dir = os.path.join(root_dir, "val", "masks")

    val_imgs = sorted(glob.glob(os.path.join(val_img_dir, "img*.tif")))
    val_masks = [os.path.join(val_mask_dir, os.path.basename(p).replace("img", "mask")) for p in val_imgs]

    test_img_dir = os.path.join(root_dir, "test", "images")
    test_mask_dir = os.path.join(root_dir, "test", "masks")

    test_imgs = sorted(glob.glob(os.path.join(test_img_dir, "img*.tif")))
    test_masks = [os.path.join(test_mask_dir, os.path.basename(p).replace("img", "mask")) for p in test_imgs]
    
    return train_imgs, train_masks, val_imgs, val_masks, test_imgs, test_masks


def make_loader(imgs, masks, selected_bands, batch_size, shuffle, num_workers, compute_fn=None):
    dataset = ShorelineDataset(imgs, masks, selected_bands, compute_fn=compute_fn)
    return DataLoader(
        dataset,
        batch_size=batch_size,
        shuffle=shuffle,
        num_workers=num_workers,
        pin_memory=True,
        persistent_workers=num_workers > 0,
        prefetch_factor=2 if num_workers > 0 else None
    )

def make_test_loader(test_imgs, test_masks, selected_bands, batch_size,
                     num_workers=4, compute_fn=None):
    """Build a single DataLoader for the test split — no dummy data needed."""
    return make_loader(
        test_imgs, test_masks, selected_bands,
        batch_size, shuffle=False,
        num_workers=num_workers, compute_fn=compute_fn
    )

def prepare_dataset(batch_size, train_imgs, train_masks, val_imgs, val_masks,
                    selected_bands, test_imgs=None, test_masks=None,
                    num_workers=4, compute_fn=None):
    
    train_loader = make_loader(train_imgs, train_masks, selected_bands,
                               batch_size, shuffle=True,  num_workers=num_workers,
                               compute_fn=compute_fn)
    val_loader   = make_loader(val_imgs,   val_masks,   selected_bands,
                               batch_size, shuffle=False, num_workers=num_workers,
                               compute_fn=compute_fn)
    
    for images, masks in train_loader:
        print(f"\nImage batch shape: {images.shape}")  # (B, C, H, W)
        print(f" Mask batch shape: {masks.shape}\n")
        break  # just check the first batch

    if test_imgs is not None and test_masks is not None:
        test_loader = make_loader(test_imgs, test_masks, selected_bands,
                          batch_size, shuffle=False, num_workers=num_workers,
                          compute_fn=compute_fn)
        return train_loader, val_loader, test_loader

    return train_loader, val_loader